import { GoogleLogin } from "@react-oauth/google";
import { useNavigate } from "react-router-dom";

function Login() {
  const navigate = useNavigate();

  return (
    <div>
      <h2>Login</h2>

      <GoogleLogin
        onSuccess={(res) => {
          console.log(res.credential); // Google ID token
          navigate("/dashboard");     // 👈 redirect
        }}
        onError={() => {
          alert("Login Failed");
        }}
      />
    </div>
  );
}

export default Login;
